+
+	cluster := r.URL.Query().Get("cluster")
+	if cluster == "" {
+		json.NewEncoder(w).Encode(map[string]interface{}{"nodes": []interface{}{}, "error": "cluster parameter required"})
+		return
+	}
+
+	ctx, cancel := context.WithTimeout(r.Context(), 15*time.Second)
